import React, { useEffect, useState } from 'react';
import { ActivityIndicator, Alert, Button, SafeAreaView, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const AUTH_KEY = '@authenticated';
const PASSWORD_KEY = '@saved_password';

const rnBiometrics = new ReactNativeBiometrics({ allowDeviceCredentials: true });

const LoginScreen = ({ onAuthenticated }) => {
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState(null);

  useEffect(() => {
    const checkBiometrics = async () => {
      try {
        const { available, biometryType } = await rnBiometrics.isSensorAvailable();
        setBiometricAvailable(available);
        setBiometricType(biometryType);
      } catch (e) {
        setBiometricAvailable(false);
        setBiometricType(null);
      }
    };
    checkBiometrics();
  }, []);

  const saveAuthenticatedFlag = async () => {
    await AsyncStorage.setItem(AUTH_KEY, 'true');
  };

  const handleBiometricLogin = async () => {
    try {
      setLoading(true);
      const { success } = await rnBiometrics.simplePrompt({
        promptMessage: biometricType === 'FaceID' ? 'Authenticate with Face ID' : 'Authenticate with biometrics',
      });

      if (success) {
        await saveAuthenticatedFlag();
        onAuthenticated();
      }
    } catch (e) {
      Alert.alert('Authentication failed', 'Biometric authentication was not successful.');
    } finally {
      setLoading(false);
    }
  };

  const handlePasswordLogin = async () => {
    try {
      setLoading(true);

      const savedPassword = await AsyncStorage.getItem(PASSWORD_KEY);

      if (!savedPassword) {
        await AsyncStorage.setItem(PASSWORD_KEY, password);
        await saveAuthenticatedFlag();
        onAuthenticated();
        return;
      }

      if (password === savedPassword) {
        await saveAuthenticatedFlag();
        onAuthenticated();
      } else {
        Alert.alert('Invalid password', 'Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={{ flex: 1, justifyContent: 'center', padding: 24 }}>
      <View style={{ gap: 16 }}>
        <Text style={{ fontSize: 24, fontWeight: '700', textAlign: 'center' }}>Login</Text>

        {biometricAvailable ? (
          <Button
            title={loading ? 'Authenticating...' : `Use ${biometricType === 'FaceID' ? 'Face ID' : 'Biometrics'}`}
            onPress={handleBiometricLogin}
            disabled={loading}
          />
        ) : (
          <Text style={{ textAlign: 'center' }}>Biometrics unavailable. Use password login below.</Text>
        )}

        <TextInput
          value={password}
          onChangeText={setPassword}
          placeholder="Password"
          secureTextEntry
          autoCapitalize="none"
          style={{
            borderWidth: 1,
            borderColor: '#ccc',
            borderRadius: 8,
            paddingHorizontal: 12,
            paddingVertical: 10,
          }}
        />

        <Button title={loading ? 'Please wait...' : 'Login with Password'} onPress={handlePasswordLogin} disabled={loading || !password} />
      </View>
    </SafeAreaView>
  );
};

const HomeScreen = ({ onLogout }) => {
  const handleLogout = async () => {
    await AsyncStorage.removeItem(AUTH_KEY);
    onLogout();
  };

  return (
    <SafeAreaView style={{ flex: 1, justifyContent: 'center', padding: 24 }}>
      <View style={{ gap: 16, alignItems: 'center' }}>
        <Text style={{ fontSize: 24, fontWeight: '700' }}>Home Screen</Text>
        <Button title="Logout" onPress={handleLogout} />
      </View>
    </SafeAreaView>
  );
};

export default function App() {
  const [checkingAuth, setCheckingAuth] = useState(true);
  const [authenticated, setAuthenticated] = useState(false);

  useEffect(() => {
    const bootstrap = async () => {
      const authFlag = await AsyncStorage.getItem(AUTH_KEY);
      setAuthenticated(authFlag === 'true');
      setCheckingAuth(false);
    };
    bootstrap();
  }, []);

  if (checkingAuth) {
    return (
      <SafeAreaView style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
        <ActivityIndicator size="large" />
      </SafeAreaView>
    );
  }

  return authenticated ? (
    <HomeScreen onLogout={() => setAuthenticated(false)} />
  ) : (
    <LoginScreen onAuthenticated={() => setAuthenticated(true)} />
  );
}